import * as fs from 'fs/promises';
import * as path from 'path';
import dotenv from 'dotenv';
import chalk from 'chalk';
import {
  CodeMieConfigOptions,
  ProviderProfile,
  MultiProviderConfig,
  CodeMieIntegrationInfo,
